import subprocess
import anthropic

client = anthropic.Anthropic()

def run_tests(test_command: str, working_dir: str) -> dict:
    """Run tests and return structured result for agent consumption."""
    result = subprocess.run(
        test_command,
        shell=True,
        cwd=working_dir,
        capture_output=True,
        text=True,
        timeout=120
    )
    return {
        "exit_code": result.returncode,
        "stdout": result.stdout[-3000:],  # Last 3000 chars to avoid context bloat
        "stderr": result.stderr[-1000:],
        "passed": result.returncode == 0,
        "summary": "PASSED" if result.returncode == 0 else "FAILED"
    }

def verification_loop(task: str, test_command: str, working_dir: str, max_turns: int = 30):
    """
    Agent loop with explicit verification after each action.
    Uses test results to drive iteration decisions.
    """
    messages = [{"role": "user", "content": task}]

    tools = [
        {
            "name": "run_tests",
            "description": "Run the test suite and return pass/fail results with error messages",
            "input_schema": {
                "type": "object",
                "properties": {
                    "test_filter": {
                        "type": "string",
                        "description": "Optional: run only tests matching this pattern"
                    }
                }
            }
        },
        # ... other tools (read, write, edit, bash)
    ]

    for turn in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-5",
            max_tokens=4096,
            tools=tools,
            messages=messages
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return "Task complete"

        # Execute tools and append results
        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            if block.name == "run_tests":
                test_filter = block.input.get("test_filter", "")
                cmd = f"{test_command} {test_filter}".strip()
                result = run_tests(cmd, working_dir)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result)  # Structured for Claude to parse
                })

        messages.append({"role": "user", "content": tool_results})

    return "Max turns reached"

import json

class AgentLoop:
    """A bounded agent loop with explicit termination conditions."""

    def __init__(self, client, tools, max_turns=30, max_consecutive_failures=5):
        self.client = client
        self.tools = tools
        self.max_turns = max_turns
        self.max_consecutive_failures = max_consecutive_failures
        self.consecutive_failures = 0
        self.total_tokens_used = 0
        self.token_budget = 100_000  # Hard limit

    def should_stop(self, response, turn: int) -> tuple[bool, str]:
        """Check all termination conditions and return (should_stop, reason)."""
        if response.stop_reason == "end_turn":
            return True, "task_complete"
        if turn >= self.max_turns:
            return True, f"max_turns_reached ({self.max_turns})"
        if self.consecutive_failures >= self.max_consecutive_failures:
            return True, f"max_failures_reached ({self.consecutive_failures})"
        if self.total_tokens_used > self.token_budget:
            return True, f"token_budget_exceeded ({self.total_tokens_used})"
        return False, ""

    def record_verification(self, passed: bool):
        """Track consecutive failures for early stopping."""
        if passed:
            self.consecutive_failures = 0
        else:
            self.consecutive_failures += 1

    def run(self, task: str, system_prompt: str = "") -> dict:
        """Run the agent loop with full termination condition checking."""
        messages = [{"role": "user", "content": task}]

        for turn in range(self.max_turns + 1):
            response = self.client.messages.create(
                model="claude-sonnet-4-5",
                max_tokens=4096,
                system=system_prompt,
                tools=self.tools,
                messages=messages
            )

            self.total_tokens_used += response.usage.input_tokens + response.usage.output_tokens
            messages.append({"role": "assistant", "content": response.content})

            should_stop, reason = self.should_stop(response, turn)
            if should_stop:
                return {"status": reason, "turns": turn, "tokens": self.total_tokens_used}

            # Execute tools, check verification results
            tool_results = self._execute_tools(response.content)
            messages.append({"role": "user", "content": tool_results})

        return {"status": "loop_exhausted", "turns": self.max_turns, "tokens": self.total_tokens_used}

